public class prey {

private double[] preyPred = {300, 20};
double[] a = {0.1, 0.01};
double[] b = {0.01, 0.00002};
int n = 20;
double r, x, z, c;

public double setPreyPred(double[] preyPred, double[] a, double[] b, int n) {
this.preyPred = preyPred;
this.a = a;
this.b = b;
this.n = n;

if (n == 0) {
return 1;
} else {
c = preyPred[0] * (1 + a[0] - a[1] * preyPred[1]);
r = preyPred[1] * (1 - b[0] + b[1] * preyPred[0]);

for (int i = 0; i < n; i++) {
x = c * (1 + a[0] - a[1] * r);
double temp = x;
x = c;
c = temp;
//----------------------------------------------------------------
z = r * (1 - b[0] + b[1] * c);
double tmp = z;
z = r;
r = tmp;
}
System.out.print("For: " + n + " period  there are: ");
System.out.printf("%1.2f", x);
System.out.printf(" snowshoe hares and : ");
System.out.printf("%1.2f", z);
System.out.printf(" lynxes \n");

}

return +setPreyPred(preyPred, a, b, n - 1);
}

public double getPrey() {
return this.setPreyPred(preyPred, a, b, n);
}

public static void main(String[] argc) {
prey show = new prey();
show.getPrey();
}
}

