double[] preyPredLV(double[] preyPred, double[] a, double[] b, int n){

double [] H = new double[n+1];
H[0] = preyPred[0];
double [] L = new double[n+1];
L[0] = preyPred[1];

for (int i=0; i<n; i++){
    H[i + 1] = H[i] * (1 + a[0] - a[1]*L[i]);
