    /* 
	 * Delete the first occurrence of a value
	 * Return a boolean if the delete was succesfull
	 */
	public boolean deleteFirstOccurrence(E info){
		boolean success = false;

		// Is the list empty?
		if (first != null){
			// We review if we only have 1 node
			if (first.getInfo().equals(info)){
				if (first.getNext() != null){
					first = first.getNext();
				} else {
					first = null;
				}
				success = true;

			} else {
				Node<E> current = first.getNext();
				Node<E> previous = first;

				while (current != null ){
					if (current.getInfo().equals(info)){
						success = true;
						previous.setNext(current.getNext());
						break;
					} else {
						previous = previous.getNext();
						current = current.getNext();
					}
				}
			}
		}

		return success;
	}

