public class ParenthesisMatch {
    public int parenthesisCount (String parenthesis) throws Exception {
        int count = 0;
        int max = parenthesis.length()/2;
        for(int i = 0; i < parenthesis.length() && count < 0; i++) {
            if(parenthesis.charAt(i) == '(')
                count++;
            else if(parenthesis.charAt(i) == ')')
                count--;
        }
        if(count != 0 || parenthesis.length() % 2 != 0)
            throw new Exception(parenthesis + "is not well-ordered or balanced");
        return max;
    }
}

